def gen(rng, size):
    n = rng.randint(1, max(1, min(size, 200)))
    vals = rng.sample(range(0, 1001), n)
    arr = [vals[0]]
    pool = vals[1:]
    pi = 0
    while pi < len(pool):
        if rng.random() < 0.75:
            arr.append(pool[pi]); pi += 1
        else:
            arr.append(None)
    while arr and arr[-1] is None:
        arr.pop()
    return [arr]

