class Solution:
    def lcaDeepestLeaves(self, root):
        # independent two-pass: find max depth, collect deepest leaves with their
        # ancestor paths, then take the lowest shared ancestor across those paths.
        levels = {}
        path = {}
        max_depth = [0]
        def dfs(node, depth, anc):
            if node is None:
                return
            cur = anc + [node]
            path[id(node)] = cur
            if node.left is None and node.right is None:
                levels.setdefault(depth, []).append(node)
                if depth > max_depth[0]:
                    max_depth[0] = depth
            dfs(node.left, depth + 1, cur)
            dfs(node.right, depth + 1, cur)
        dfs(root, 0, [])
        deepest = levels[max_depth[0]]
        common = path[id(deepest[0])]
        for leaf in deepest[1:]:
            p = path[id(leaf)]
            new_common = []
            for a, b in zip(common, p):
                if a is b:
                    new_common.append(a)
                else:
                    break
            common = new_common
        return common[-1]

