class Solution:
    def lcaDeepestLeaves(self, root):
        def helper(node):
            if node is None:
                return 0, None
            ld, la = helper(node.left)
            rd, ra = helper(node.right)
            if ld == rd:
                return ld + 1, node
            if ld > rd:
                return ld + 1, la
            return rd + 1, ra
        return helper(root)[1]

